          <div>
            <h3 className="text-lg font-bold text-slate-900 mb-2">Contact Information</h3>
            <p className="text-slate-600 mb-6">
              Fill out the form or reach out directly via email.
            </p>

            <a href="mailto:arupsis3@gatech.edu" className="flex items-center text-primary hover:text-blue-700 transition-colors mb-4">
              <div className="w-10 h-10 bg-blue-50 rounded-full flex items-center justify-center mr-3 text-primary">
                <Icon name="mail" size={20} />
              </div>
              <span className="font-medium">arupsis3@gatech.edu</span>
            </a>

            <a 
              href="https://www.linkedin.com/in/adam-rupsis/" 
              target="_blank" 
              rel="noopener noreferrer"
              className="flex items-center text-primary hover:text-blue-700 transition-colors"
            >
              <div className="w-10 h-10 bg-blue-50 rounded-full flex items-center justify-center mr-3 text-primary">
                <Icon name="linkedin" size={20} />
              </div>
              <span className="font-medium">/in/adam-rupsis</span>
            </a>
          </div>
        </div>

        {/* Form */}
        <div className="md:col-span-2 bg-white rounded-2xl shadow-lg border border-slate-100 p-8">
          {isSubmitted ? (
            <div className="h-full flex flex-col items-center justify-center text-center py-12">
              <div className="w-16 h-16 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-4">
                <Icon name="arrow-right" size={32} className="transform -rotate-45" /> {/* Checkmark-ish */}
