              <h3 className="text-2xl font-bold text-slate-900 mb-2">Opening Email Client...</h3>
              <p className="text-slate-600 mb-6">Please send the pre-filled email to complete your message.</p>
              <button 
                onClick={() => { setIsSubmitted(false); setFormState({ name: '', email: '', message: '' }); }}
                className="text-primary font-medium hover:underline"
              >
                Send another message
              </button>
            </div>
          ) : (
            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label htmlFor="name" className="block text-sm font-medium text-slate-700 mb-2">Name</label>
                  <input
                    type="text"
                    id="name"
                    name="name"
                    required
                    value={formState.name}
                    onChange={handleChange}
